/* Minimal local adapter for @googlemaps/markerclusterer-compatible construction.
   VERSION: local-m8-compat
   This keeps Milestone 8 offline-capable; replace with pinned upstream browser bundle when desired. */
(function(){class MarkerClusterer{constructor(opts){this.map=opts.map;this.markers=opts.markers||[];}clearMarkers(){this.markers.forEach(m=>{if(m.map!==undefined)m.map=null;else if(m.setMap)m.setMap(null)});this.markers=[];}addMarkers(markers){this.markers=this.markers.concat(markers||[]);}}window.markerClusterer={MarkerClusterer};})();
